import os, requests

r = requests.post(
    "https://u22a8.ai/v1/models",
    headers={"Authorization": f"Bearer {os.environ['U22A8_API_KEY']}"},
    json={
        "handle": "acme.support-tone",
        "description": "Warmth and clarity of support replies",
    },
)
print(r.json()["handle"], r.json()["state"])  # acme.support-tone draft

import os, requests

r = requests.post(
    "https://u22a8.ai/v1/models/u22a8.commit-message/compare",
    headers={"Authorization": f"Bearer {os.environ['U22A8_API_KEY']}"},
    json={
        "a": "fix bug",
        "b": "Fix race condition in worker dispatch by draining the in-flight queue before shutdown",
    },
)
print(r.json()["improvement"], r.json()["per_trait"])

